PRAGMA foreign_keys=ON;
CREATE TABLE schema_migrations(version TEXT PRIMARY KEY, applied_at TEXT NOT NULL);
CREATE TABLE users(id TEXT PRIMARY KEY, username TEXT NOT NULL UNIQUE, email TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, email_verified INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL);
CREATE TABLE revoked_tokens(jti TEXT PRIMARY KEY, expires_at TEXT NOT NULL);
CREATE TABLE projects(id TEXT PRIMARY KEY, owner_id TEXT NOT NULL REFERENCES users(id), title TEXT NOT NULL, question TEXT NOT NULL, abstract TEXT NOT NULL DEFAULT '', visibility TEXT NOT NULL DEFAULT 'private', status TEXT NOT NULL DEFAULT 'active', tags TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX ix_projects_owner ON projects(owner_id); CREATE INDEX ix_projects_visibility ON projects(visibility);
CREATE TABLE project_members(project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE, role TEXT NOT NULL, created_at TEXT NOT NULL, PRIMARY KEY(project_id,user_id));
CREATE TABLE branches(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, name TEXT NOT NULL, parent_id TEXT REFERENCES branches(id), base_event_id TEXT, created_by TEXT NOT NULL REFERENCES users(id), created_at TEXT NOT NULL, UNIQUE(project_id,name));
CREATE TABLE nodes(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, branch_id TEXT REFERENCES branches(id), run_id TEXT, kind TEXT NOT NULL, title TEXT NOT NULL, content TEXT NOT NULL, status TEXT NOT NULL, position TEXT NOT NULL, provenance TEXT NOT NULL, version INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX ix_nodes_project_kind ON nodes(project_id,kind);
CREATE TABLE edges(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, branch_id TEXT REFERENCES branches(id), source_id TEXT NOT NULL REFERENCES nodes(id) ON DELETE CASCADE, target_id TEXT NOT NULL REFERENCES nodes(id) ON DELETE CASCADE, edge_type TEXT NOT NULL, metadata TEXT NOT NULL, created_at TEXT NOT NULL, UNIQUE(project_id,source_id,target_id,edge_type));
CREATE TABLE claims(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, node_id TEXT NOT NULL UNIQUE REFERENCES nodes(id) ON DELETE CASCADE, statement TEXT NOT NULL, latex TEXT, assumptions TEXT NOT NULL, status TEXT NOT NULL, confidence REAL NOT NULL, proposed_by TEXT NOT NULL, required_capabilities TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX ix_claims_status ON claims(project_id,status);
CREATE TABLE evidence(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, node_id TEXT NOT NULL UNIQUE REFERENCES nodes(id) ON DELETE CASCADE, claim_id TEXT NOT NULL REFERENCES claims(id) ON DELETE CASCADE, evidence_type TEXT NOT NULL, stance TEXT NOT NULL, title TEXT NOT NULL, content TEXT NOT NULL, source TEXT NOT NULL, reliability REAL NOT NULL, reproducibility TEXT NOT NULL, assumptions TEXT NOT NULL, independence_group TEXT, immutable_hash TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE reviews(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, claim_id TEXT NOT NULL REFERENCES claims(id) ON DELETE CASCADE, actor TEXT NOT NULL, stance TEXT NOT NULL, reason TEXT NOT NULL, assumptions TEXT NOT NULL, confidence REAL NOT NULL, independence_group TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE dead_ends(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, branch_id TEXT REFERENCES branches(id), run_id TEXT, node_id TEXT NOT NULL UNIQUE REFERENCES nodes(id), target_id TEXT, approach TEXT NOT NULL, normalized_strategy TEXT NOT NULL, assumptions TEXT NOT NULL, method TEXT NOT NULL, failure TEXT NOT NULL, lesson TEXT NOT NULL, applies_where TEXT NOT NULL, may_not_apply_where TEXT NOT NULL, discovered_by TEXT NOT NULL, fingerprint TEXT NOT NULL, search_text TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX ix_dead_ends_fingerprint ON dead_ends(fingerprint);
CREATE TABLE pipelines(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, name TEXT NOT NULL, version INTEGER NOT NULL, definition TEXT NOT NULL, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE runs(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, pipeline_id TEXT REFERENCES pipelines(id), branch_id TEXT REFERENCES branches(id), status TEXT NOT NULL, goal TEXT NOT NULL, execution_mode TEXT NOT NULL, checkpoint TEXT NOT NULL, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX ix_runs_project_status ON runs(project_id,status);
CREATE TABLE events(id TEXT PRIMARY KEY, project_id TEXT REFERENCES projects(id) ON DELETE CASCADE, run_id TEXT REFERENCES runs(id) ON DELETE CASCADE, branch_id TEXT REFERENCES branches(id), actor_id TEXT NOT NULL, actor_type TEXT NOT NULL, event_type TEXT NOT NULL, payload TEXT NOT NULL, parent_event_id TEXT, correlation_id TEXT NOT NULL, idempotency_key TEXT UNIQUE, schema_version TEXT NOT NULL, integrity_hash TEXT NOT NULL, timestamp TEXT NOT NULL);
CREATE INDEX ix_events_project_time ON events(project_id,timestamp); CREATE INDEX ix_events_run_time ON events(run_id,timestamp);
CREATE TABLE provider_credentials(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE, provider TEXT NOT NULL, encrypted_key TEXT NOT NULL, key_fingerprint TEXT NOT NULL, status TEXT NOT NULL, last_used_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(user_id,provider));
CREATE INDEX ix_credentials_owner_provider ON provider_credentials(user_id,provider);
CREATE TABLE ledger_entries(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), run_id TEXT REFERENCES runs(id), entry_type TEXT NOT NULL, amount_micros INTEGER NOT NULL, currency TEXT NOT NULL, metadata TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX ix_ledger_user_time ON ledger_entries(user_id,created_at);
CREATE TABLE credit_reservations(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), run_id TEXT REFERENCES runs(id), reserved_micros INTEGER NOT NULL, settled_micros INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE public_snapshots(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), version INTEGER NOT NULL, payload TEXT NOT NULL, integrity_hash TEXT NOT NULL, visible INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, UNIQUE(project_id,version));
CREATE INDEX ix_snapshots_project_version ON public_snapshots(project_id,version);
CREATE TABLE literature_sources(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id), source_type TEXT NOT NULL, title TEXT NOT NULL, authors TEXT NOT NULL, doi TEXT, arxiv_id TEXT, url TEXT, metadata TEXT NOT NULL, reliability REAL NOT NULL, retrieved_at TEXT NOT NULL);
CREATE TABLE benchmark_runs(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), task_id TEXT NOT NULL, mode TEXT NOT NULL, metrics TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE payment_events(provider_event_id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), status TEXT NOT NULL, amount_micros INTEGER NOT NULL, payload_hash TEXT NOT NULL, created_at TEXT NOT NULL);
